"use strict";(self.webpackChunkmagento2_hyva_jewellery_theme_docs=self.webpackChunkmagento2_hyva_jewellery_theme_docs||[]).push([[8912],{8653(e,t,a){a.r(t),a.d(t,{comp:()=>o,data:()=>s});var r=a(641);const n={},o=(0,a(6262).A)(n,[["render",function(e,t){return(0,r.uX)(),(0,r.CE)("div",null,[...t[0]||(t[0]=[(0,r.Fv)('<h1 id="magento-2-hyva-jewellery-theme" tabindex="-1"><a class="header-anchor" href="#magento-2-hyva-jewellery-theme"><span>Magento 2 Hyvä Jewellery Theme</span></a></h1><p>The Magento 2 Hyvä Jewellery Theme is made for jewellery and fashion accessory stores. It gives your store a clean homepage, simple navigation, product listing pages, product detail pages, cart, checkout, account pages, wishlist pages, contact page, and a branded 404 page. It is also Agent Ready, so the storefront can work well for modern AI browsing checks and agent-assisted shopping flows.</p><p>This guide explains what to check first, how to activate the theme, and where to manage the main storefront areas.</p><p><img src="/hyva-jewelry-theme/screenshots/home-hero.png" alt="Magento 2 Hyvä Jewellery Theme homepage"></p><h2 id="what-is-included" tabindex="-1"><a class="header-anchor" href="#what-is-included"><span>What is included</span></a></h2><table><thead><tr><th>Area</th><th>What it helps you do</th><th>Guide</th></tr></thead><tbody><tr><td>Requirements</td><td>Check the store requirements before setup.</td><td><a href="/hyva-jewelry-theme/requirements.html" target="_blank" rel="noopener noreferrer">Open requirements</a></td></tr><tr><td>Installation</td><td>Add the theme to the Magento store and prepare it for use.</td><td><a href="/hyva-jewelry-theme/installation.html" target="_blank" rel="noopener noreferrer">Open installation</a></td></tr><tr><td>Activation</td><td>Select the theme for the correct store view from Magento Admin.</td><td><a href="/hyva-jewelry-theme/activation.html" target="_blank" rel="noopener noreferrer">Open activation</a></td></tr><tr><td>Homepage</td><td>Show the hero banner, category carousel, new arrivals, and featured products.</td><td><a href="/hyva-jewelry-theme/homepage/overview.html" target="_blank" rel="noopener noreferrer">Open homepage guide</a></td></tr><tr><td>Header and footer</td><td>Manage the top bar, logo area, menu, search, cart, language, currency, and footer.</td><td><a href="/hyva-jewelry-theme/chrome/overview.html" target="_blank" rel="noopener noreferrer">Open header and footer guide</a></td></tr><tr><td>Store pages</td><td>Review category, search, product, cart, and checkout pages.</td><td><a href="/hyva-jewelry-theme/pages/category.html" target="_blank" rel="noopener noreferrer">Open store pages guide</a></td></tr><tr><td>Agent Ready</td><td>Check that the storefront is fast, easy to browse, and ready for agent-assisted shopping flows.</td><td>See the performance preview below.</td></tr></tbody></table><h2 id="agent-ready" tabindex="-1"><a class="header-anchor" href="#agent-ready"><span>Agent Ready</span></a></h2><p>The theme is built on Hyvä for a fast storefront experience. It is prepared for agent browsing checks, so AI tools can understand the page structure, read key storefront content, and move through shopping pages more easily.</p><p>The example check below shows strong desktop performance and a passing agentic browsing result for the demo storefront.</p><p><img src="/hyva-jewelry-theme/screenshots/agentic-performance-desktop.png" alt="Desktop performance and agentic browsing check for the Magento 2 Hyvä Jewellery Theme"></p><h2 id="before-you-start" tabindex="-1"><a class="header-anchor" href="#before-you-start"><span>Before you start</span></a></h2><p>Make sure the store has the basic data needed for a good preview:</p><ol><li>Add active categories and include them in the menu.</li><li>Add products with names, prices, images, and stock.</li><li>Set the default store view, language, and currency.</li><li>Check that Hyvä is installed and active on the Magento project.</li><li>Keep the Magento cache ready to refresh after changing the theme.</li></ol><h2 id="getting-started" tabindex="-1"><a class="header-anchor" href="#getting-started"><span>Getting started</span></a></h2><p>Follow these pages in order:</p><ol><li>Read the <a href="/hyva-jewelry-theme/requirements.html" target="_blank" rel="noopener noreferrer">Requirements</a>.</li><li>Complete the <a href="/hyva-jewelry-theme/installation.html" target="_blank" rel="noopener noreferrer">Installation</a>.</li><li>Activate the theme from <a href="/hyva-jewelry-theme/activation.html" target="_blank" rel="noopener noreferrer">Activate the Theme</a>.</li><li>Open the storefront and check the homepage, category page, search page, product page, cart, and checkout.</li><li>If something does not look right, open <a href="/hyva-jewelry-theme/help/troubleshooting.html" target="_blank" rel="noopener noreferrer">Troubleshooting</a>.</li></ol><h2 id="after-activation" tabindex="-1"><a class="header-anchor" href="#after-activation"><span>After activation</span></a></h2><p>After the theme is active, check these storefront areas:</p><table><thead><tr><th>Store area</th><th>What to check</th></tr></thead><tbody><tr><td>Homepage</td><td>Hero banner, category carousel, new arrival products, and featured products.</td></tr><tr><td>Header</td><td>Logo, menu, search box, customer account link, wishlist, compare, and cart.</td></tr><tr><td>Footer</td><td>Newsletter, store links, social links, and payment icons.</td></tr><tr><td>Category page</td><td>Product grid, filters, sorting, pagination, and product cards.</td></tr><tr><td>Search page</td><td>Search field, result count, filters, pagination, and product cards.</td></tr><tr><td>Product page</td><td>Product images, price, options, quantity, add to cart, wishlist, and reviews.</td></tr><tr><td>Cart and checkout</td><td>Cart drawer, cart page, checkout steps, address forms, shipping, payment, and order success page.</td></tr></tbody></table><h2 id="need-help" tabindex="-1"><a class="header-anchor" href="#need-help"><span>Need help</span></a></h2><p>Use the <a href="/hyva-jewelry-theme/help/troubleshooting.html" target="_blank" rel="noopener noreferrer">Troubleshooting</a> page for common setup issues. Use the <a href="/hyva-jewelry-theme/help/faq.html" target="_blank" rel="noopener noreferrer">FAQ</a> page for quick answers about the theme.</p>',21)])])}]]),s=JSON.parse('{"path":"/hyva-jewelry-theme/introduction.html","title":"Magento 2 Hyvä Jewellery Theme","lang":"en-US","frontmatter":{"title":"Magento 2 Hyvä Jewellery Theme"},"headers":[{"level":2,"title":"What is included","slug":"what-is-included","link":"#what-is-included","children":[]},{"level":2,"title":"Agent Ready","slug":"agent-ready","link":"#agent-ready","children":[]},{"level":2,"title":"Before you start","slug":"before-you-start","link":"#before-you-start","children":[]},{"level":2,"title":"Getting started","slug":"getting-started","link":"#getting-started","children":[]},{"level":2,"title":"After activation","slug":"after-activation","link":"#after-activation","children":[]},{"level":2,"title":"Need help","slug":"need-help","link":"#need-help","children":[]}],"git":{"contributors":[{"name":"anikesh kumar","username":"","email":"anikesh.kumar204@webkul.in","commits":1}],"changelog":[{"hash":"65ee1538c72e98b02c838952f96993746b91fe68","time":1783608557000,"email":"anikesh.kumar204@webkul.in","author":"anikesh kumar","message":"init"}]},"filePathRelative":"introduction.md"}')}}]);